import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.6ZJjlmu_.js";const p=JSON.parse('{"title":"EventBus API","description":"","frontmatter":{},"headers":[],"relativePath":"reference/event-bus-api.md","filePath":"reference/event-bus-api.md"}'),n={name:"reference/event-bus-api.md"};function d(s,e,i,c,l,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="eventbus-api" tabindex="-1">EventBus API <a class="header-anchor" href="#eventbus-api" aria-label="Permalink to &quot;EventBus API&quot;">​</a></h1><p>This page summarizes the <strong>public</strong> <code>EventBus</code> surface area as used by Event Monitor. Names and signatures follow the Unity package; always verify in your installed version.</p><h2 id="runtime-settings" tabindex="-1">Runtime settings <a class="header-anchor" href="#runtime-settings" aria-label="Permalink to &quot;Runtime settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Member</th><th>Purpose</th></tr></thead><tbody><tr><td><code>IsRecording</code></td><td>When <code>false</code>, new records are not appended.</td></tr><tr><td><code>EnablePayloadCapture</code></td><td>When <code>true</code>, payload capture paths are active (toolbar + <code>TagPayload</code>).</td></tr><tr><td><code>CaptureStackTraces</code></td><td>When <code>true</code>, new records may include stack traces (higher overhead).</td></tr></tbody></table><p>Editor session persistence of these flags is handled by Editor-only settings code.</p><h2 id="manual-recording-advanced" tabindex="-1">Manual recording (advanced) <a class="header-anchor" href="#manual-recording-advanced" aria-label="Permalink to &quot;Manual recording (advanced)&quot;">​</a></h2><p>These are safe to call from <strong>custom tooling</strong> or tests. Game code usually relies on <strong>ILPP</strong> instead.</p><table tabindex="0"><thead><tr><th>Method</th><th>Use</th></tr></thead><tbody><tr><td><code>RecordSubscribe(eventName, ownerType, ownerInstanceId, subscriberType, subscriberMethod)</code></td><td>Append a <strong>SUB</strong> row and update live state.</td></tr><tr><td><code>RecordUnsubscribe(...)</code></td><td>Append an <strong>UNSUB</strong> row and update live state.</td></tr><tr><td><code>RecordInvoke(eventName, ownerType, ownerInstanceId, subscriberCount, parameters)</code></td><td>Append an <strong>INVOKE</strong> row.</td></tr></tbody></table><h2 id="payload-tagging" tabindex="-1">Payload tagging <a class="header-anchor" href="#payload-tagging" aria-label="Permalink to &quot;Payload tagging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Use</th></tr></thead><tbody><tr><td><code>TagPayload(params object[] args)</code></td><td>Attach arguments to the <strong>next</strong> invocation on this thread when payload capture is enabled. Call immediately before firing the event.</td></tr></tbody></table><h2 id="injected-entry-points-do-not-call-from-gameplay" tabindex="-1">Injected entry points (do not call from gameplay) <a class="header-anchor" href="#injected-entry-points-do-not-call-from-gameplay" aria-label="Permalink to &quot;Injected entry points (do not call from gameplay)&quot;">​</a></h2><p>ILPP injects calls to <strong>static</strong> helpers such as:</p><ul><li><code>RecordSubscribeDelegate(string eventName, string ownerType, int instanceId, Delegate handler)</code></li><li><code>RecordUnsubscribeDelegate(...)</code></li><li><code>RecordInvokeDelegate(string eventName, string ownerType, int instanceId)</code></li></ul><p>They are <strong>not</strong> intended for manual use; they exist so rewritten IL can report activity with stable signatures.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Relying on injected methods from hand-written code is fragile and may break across package updates.</p></div><h2 id="ui-integration" tabindex="-1">UI integration <a class="header-anchor" href="#ui-integration" aria-label="Permalink to &quot;UI integration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Member</th><th>Purpose</th></tr></thead><tbody><tr><td><code>OnRecordAdded</code></td><td>Raised when a record is appended (Editor window repaints).</td></tr></tbody></table><h2 id="stats-and-queries" tabindex="-1">Stats and queries <a class="header-anchor" href="#stats-and-queries" aria-label="Permalink to &quot;Stats and queries&quot;">​</a></h2><p>The package exposes counters and ring-buffer stats (for example total records, invoke counts) for the <strong>Stats</strong> tab and toolbar. Exact property names may vary by version — inspect <code>EventBus</code> in your IDE.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../how-to/payload-capture.html">Capture invocation payloads</a></li><li><a href="./il-limitations.html">IL patterns and limitations</a></li></ul>',21)])])}const g=t(n,[["render",d]]);export{p as __pageData,g as default};
